import React, { useState } from 'react';
import quizTopics from './quizTopics';
import QuizBuilder, { fetchQuiz, QuizBoard } from './QuizBuilder';

function PredefinedQuizList() {
  const [selectedTopic, setSelectedTopic] = useState(null);
  const [quiz, setQuiz] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  // When a topic is selected, fetch/generate a quiz for that topic
  const handleTopicSelect = async (topic) => {
    setSelectedTopic(topic);
    setLoading(true);
    setError(null);
    setQuiz(null);
    try {
      const data = await fetchQuiz({ prompt: topic.title, role: topic.role, difficulty: topic.difficulty, num_questions: 10, explanations: true });
      setQuiz({ ...data, topic });
    } catch (err) {
      setError(err.message || 'Failed to generate quiz.');
    } finally {
      setLoading(false);
    }
  };

  const handleRestart = () => {
    setQuiz(null);
    setSelectedTopic(null);
    setError(null);
  };

  if (loading) return <div style={{textAlign:'center',marginTop:'2rem'}}>Generating quiz...</div>;
  if (error) return <div style={{color:'red',textAlign:'center',marginTop:'2rem'}}>{error}</div>;

  if (quiz && selectedTopic) {
    return (
      <div style={{maxWidth: 700, margin: '0 auto', background: '#f8fafc', borderRadius: 24, boxShadow: '0 4px 32px #6366f11a', padding: 24}}>
        <button onClick={handleRestart} style={{marginBottom: 16, background: 'none', border: 'none', color: '#6366f1', fontWeight: 600, fontSize: 18, cursor: 'pointer'}}>← Back to topics</button>
        <QuizBoard quiz={quiz} onRestart={handleRestart} />
      </div>
    );
  }

  // Topic grid
  return (
    <div style={{display: 'flex', flexWrap: 'wrap', gap: 32, justifyContent: 'center', marginTop: 32, background: 'linear-gradient(90deg, #eef2ff 0%, #f8fafc 100%)', borderRadius: 24, padding: 24}}>
      {quizTopics.map(topic => (
        <div key={topic.key} style={{width: 260, background: '#fff', borderRadius: 16, boxShadow: '0 4px 24px #6366f11a', padding: 28, cursor: 'pointer', display: 'flex', flexDirection: 'column', alignItems: 'center', transition: 'box-shadow 0.2s', border: '2px solid #e0e7ff', marginBottom: 4}} onClick={() => handleTopicSelect(topic)}>
          <div style={{fontSize: 48, marginBottom: 12, background: '#f5f5fd', borderRadius: '50%', width: 70, height: 70, display: 'flex', alignItems: 'center', justifyContent: 'center', border: '2px solid #e0e7ff', boxShadow: '0 2px 8px #6366f10a'}}>{topic.emoji}</div>
          <div style={{fontWeight: 700, fontSize: 18, marginBottom: 6, textAlign: 'center'}}>{topic.title}</div>
        </div>
      ))}
    </div>
  );
}

export default PredefinedQuizList;
